import React, { useState } from "react";
import { 
  Card, 
  Typography, 
  Space, 
  Select, 
  Button, 
  Table, 
  Tag, 
  theme,
  Row,
  Col,
  Input,
  message,
  Modal,
  Form
} from "antd";
import { 
  ToolOutlined, 
  SearchOutlined, 
  PlusOutlined,
  AlertOutlined,
  CheckCircleOutlined,
  SyncOutlined,
  EditOutlined,
  DatabaseOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages } from "../dashboard/data/mockData";
import dayjs from "dayjs";

const { Title, Text } = Typography;

// Mock Data for Maintenance
const initialFaults = [
  { id: "f1", storageNm: "강남역 2번출구 보관함", type: "Network", desc: "Communication Timeout", status: "waiting", worker: "-", time: "2026-04-06 15:30:10" },
  { id: "f2", storageNm: "판교역 4번출구 보관함", type: "Sensor", desc: "Temperature high (>40C)", status: "processing", worker: "John Doe", time: "2026-04-06 12:20:00" },
  { id: "f3", storageNm: "홍대입구역 9번출구 보관함", type: "Lock", desc: "Lock release failed", status: "resolved", worker: "Admin", time: "2026-04-05 18:10:45" },
  { id: "f4", storageNm: "판교역 4번출구 보관함", type: "Fan", desc: "Fan noise reported", status: "waiting", worker: "-", time: "2026-04-06 09:00:00" },
  { id: "f5", storageNm: "명동역 6번출구 보관함", type: "Other", desc: "Touch screen unresponsive", status: "waiting", worker: "-", time: "2026-04-06 15:56:00" },
  { id: "f6", storageNm: "여의도역 5번출구 보관함", type: "Network", desc: "IP Conflict detected", status: "processing", worker: "Admin", time: "2026-04-06 15:05:00" },
  { id: "f7", storageNm: "성수역 3번출구 보관함", type: "Lock", desc: "Door open alert", status: "waiting", worker: "-", time: "2026-04-06 15:40:00" },
  { id: "f8", storageNm: "잠실역 롯데월드 보관함", type: "Sensor", desc: "Humidity low alert", status: "resolved", worker: "John Doe", time: "2026-04-06 10:00:00" },
];

export default function MaintenancePage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [searchText, setSearchText] = useState("");
  const [data, setData] = useState(initialFaults);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [form] = Form.useForm();

  const [statusFilter, setStatusFilter] = useState<string | undefined>(undefined);

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "waiting": return <AlertOutlined />;
      case "processing": return <SyncOutlined spin />;
      case "resolved": return <CheckCircleOutlined />;
      default: return null;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "waiting": return "error";
      case "processing": return "processing";
      case "resolved": return "success";
      default: return "default";
    }
  };

  const showModal = (record?: any) => {
    if (record) {
      setEditingItem(record);
      form.setFieldsValue(record);
    } else {
      setEditingItem(null);
      form.resetFields();
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    form.validateFields().then(values => {
      if (editingItem) {
        // Edit Logic
        setData(data.map(item => item.id === editingItem.id ? { ...item, ...values } : item));
        message.success(`${t("common:edit")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      } else {
        // Add Logic
        const newItem = {
          id: `f${Date.now()}`,
          ...values,
          worker: values.worker || "-",
          time: dayjs().format("YYYY-MM-DD HH:mm:ss")
        };
        setData([newItem, ...data]);
        message.success(`${t("common:add")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      }
      setIsModalOpen(false);
    });
  };

  const columns = [
    {
      title: t("storageLocker:dashboard.lockerName"),
      dataIndex: "storageNm",
      key: "storageNm",
      render: (text: string) => <Text strong>{text}</Text>,
    },
    {
      title: t("storageLocker:dashboard.faultType"),
      dataIndex: "type",
      key: "type",
      render: (type: string) => {
        const res = t(`dashboard.fault_${type.toLowerCase()}`, { ns: "storageLocker" });
        return <Tag color="blue">{res && !res.includes("fault_") ? res : type}</Tag>;
      },
    },
    {
      title: t("common:description"),
      dataIndex: "desc",
      key: "desc",
    },
    {
      title: t("storageLocker:dashboard.faultStatus"),
      dataIndex: "status",
      key: "status",
      render: (status: string) => (
        <Tag icon={getStatusIcon(status)} color={getStatusColor(status)}>
          {t(`dashboard.${status}`, { ns: "storageLocker" })}
        </Tag>
      ),
    },
    {
      title: t("common:worker"),
      dataIndex: "worker",
      key: "worker",
    },
    {
      title: t("common:datetime"),
      dataIndex: "time",
      key: "time",
    },
    {
      title: t("common:action"),
      key: "action",
      render: (_: any, record: any) => (
        <Space size="small">
          <Button type="link" size="small" icon={<EditOutlined />} onClick={() => showModal(record)}>
            {t("common:edit")}
          </Button>
        </Space>
      ),
    },
  ];

  const filteredData = data.filter(item => {
    const matchesSearch = item.storageNm.toLowerCase().includes(searchText.toLowerCase()) || item.desc.toLowerCase().includes(searchText.toLowerCase());
    const matchesStatus = statusFilter ? item.status === statusFilter : true;
    return matchesSearch && matchesStatus;
  });

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24, height: "100%", overflow: "auto" }}>
      {/* Header & Filter */}
      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[24, 16]} align="middle">
          <Col xs={24} md={8}>
            <Title level={4} style={{ margin: 0 }}>
              <ToolOutlined style={{ marginRight: 8, color: token.colorPrimary }} />
              {t("storageLocker:navigation.maintenance")}
            </Title>
          </Col>
          <Col xs={24} md={16} style={{ textAlign: "right" }}>
            <Space size="middle">
              <Select 
                placeholder={t("storageLocker:dashboard.faultStatus")} 
                style={{ width: 140 }}
                allowClear
                onChange={setStatusFilter}
                options={[
                  { value: "waiting", label: t("storageLocker:dashboard.waiting") },
                  { value: "processing", label: t("storageLocker:dashboard.processing") },
                  { value: "resolved", label: t("storageLocker:dashboard.resolved") },
                ]}
              />
              <Input 
                placeholder={t("common:search")} 
                prefix={<SearchOutlined />} 
                style={{ width: 220 }}
                onChange={e => setSearchText(e.target.value)}
              />
              <Button type="primary" icon={<PlusOutlined />} onClick={() => showModal()}>
                {t("common:add")}
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* Grid */}
      <Card bordered={false} bodyStyle={{ padding: 0 }} style={{ flex: 1, boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Table 
          columns={columns} 
          dataSource={filteredData} 
          rowKey="id"
          pagination={{ pageSize: 12 }}
          scroll={{ y: "calc(100vh - 400px)" }}
        />
      </Card>

      <div style={{ textAlign: "left", paddingLeft: 8 }}>
        <Text type="secondary">
          <AlertOutlined style={{ marginRight: 4 }} />
          {t("storageLocker:dashboard.faultList")}: {filteredData.length} {t("storageLocker:dashboard.unit_ea")}
        </Text>
      </div>

      {/* Maintenance Add/Edit Modal */}
      <Modal
        title={editingItem ? `${t("common:edit")} ${t("storageLocker:dashboard.faultStatus")}` : `${t("common:add")} ${t("storageLocker:dashboard.faultList")}`}
        open={isModalOpen}
        onOk={handleSave}
        onCancel={() => setIsModalOpen(false)}
        destroyOnClose
      >
        <Form form={form} layout="vertical" style={{ marginTop: 16 }}>
          <Form.Item name="storageNm" label={t("storageLocker:dashboard.lockerName")} rules={[{ required: true }]}>
            <Select placeholder={t("storageLocker:dashboard.selectPlaceholder")}>
              {mockStorages.map(s => <Select.Option key={s.id} value={s.name}>{s.name}</Select.Option>)}
            </Select>
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="type" label={t("storageLocker:dashboard.faultType")} rules={[{ required: true }]}>
                <Select>
                  <Select.Option value="Network">{t("storageLocker:dashboard.fault_network")}</Select.Option>
                  <Select.Option value="Sensor">{t("storageLocker:dashboard.fault_sensor")}</Select.Option>
                  <Select.Option value="Lock">{t("storageLocker:dashboard.fault_lock")}</Select.Option>
                  <Select.Option value="Fan">{t("storageLocker:dashboard.fault_fan")}</Select.Option>
                  <Select.Option value="Other">{t("storageLocker:dashboard.fault_other")}</Select.Option>
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="status" label={t("storageLocker:dashboard.faultStatus")} rules={[{ required: true }]}>
                <Select>
                  <Select.Option value="waiting">{t("storageLocker:dashboard.waiting")}</Select.Option>
                  <Select.Option value="processing">{t("storageLocker:dashboard.processing")}</Select.Option>
                  <Select.Option value="resolved">{t("storageLocker:dashboard.resolved")}</Select.Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>

          <Form.Item name="worker" label={t("common:worker")}>
            <Input prefix={<DatabaseOutlined />} placeholder={t("common:worker")} />
          </Form.Item>

          <Form.Item name="desc" label={t("common:description")} rules={[{ required: true }]}>
            <Input.TextArea rows={3} placeholder={t("storageLocker:dashboard.memoPlaceholder")} />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
